pure fn sort_descending(nums: Any) -> Any {
    sorted_nums = []
    for num in nums {
        inserted = false
        for i in range(0, length(sorted_nums)) {
            if num > sorted_nums[i] {
                sorted_nums = insert_at(sorted_nums, i, num)
                inserted = true
                break
            }
        }
        if not inserted {
            sorted_nums = append(sorted_nums, num)
        }
    }
    return sorted_nums
}

pure fn find_percentile(nums: Any, value: Number) -> Number {
    sorted_nums = sort_descending(nums)
    index = 0
    for i in range(0, length(sorted_nums)) {
        if sorted_nums[i] == value {
            index = i
            break
        }
    }
    return (index + 1) * 100 / length(sorted_nums)
}

entry main(x: Text) {
    nums = [42, 17, 8, 93, 55]
    sorted_nums = sort_descending(nums)
    percentile_42 = find_percentile(nums, 42)
    return join(["Sorted numbers: ", to_text(sorted_nums), "\nPercentile of 42: ", to_text(percentile_42), "%"], "")
}

