pure fn mean(nums: Any) -> Number {
    total = 0
    for n in nums { total = total + n }
    return total / length(nums)
}

pure fn variance(nums: Any) -> Number {
    m = mean(nums)
    var = 0
    for n in nums { var = var + (n - m)^2 }
    return var / length(nums)
}

pure fn standard_deviation(nums: Any) -> Number {
    return sqrt(variance(nums))
}

entry main(x: Text) {
    data = [10, 12, 23, 23, 16, 23, 21, 16]
    std_dev = standard_deviation(data)
    explanation = if std_dev > mean(data) { "highly variable" } else { "not highly variable" }
    return join(["Standard Deviation: ", to_text(std_dev), ", Explanation: ", explanation], "")
}

pure fn reverse_word(word: Text) -> Text {
    return join(reverse(split(word, "")), "")
}

entry main(x: Text) {
