pure fn count_lines(paragraph: Text) -> Number {
    return length(split(paragraph, "\n"))
}

pure fn count_words(paragraph: Text) -> Number {
    total = 0
    for line in split(paragraph, "\n") {
        words = split(trim(line), " ")
        total = total + length(words)
    }
    return total
}

pure fn count_chars(paragraph: Text) -> Number {
    total = 0
    for line in split(paragraph, "\n") {
        chars = split(trim(line), "")
        total = total + length(chars)
    }
    return total
}

intent rate_conciseness(paragraph: Text) -> Text {
    goal: concise_or_verbose
}

entry main(paragraph: Text) {
    lines = count_lines(paragraph)
    words = count_words(paragraph)
    chars = count_chars(paragraph)

    conciseness_rating = rate_conciseness(paragraph)

    return join([
        "Lines: ", to_text(lines), "\n",
        "Words: ", to_text(words), "\n",
        "Chars: ", to_text(chars), "\n",
        "Conciseness: ", conciseness_rating
    ], "")
}

pure fn parse_pairs(input: Text) -> Any {
