pure fn sort_by_latitude(pairs: Any) -> Any {
    sorted_pairs = sort(pairs, by=lambda x: x[1])
    return sorted_pairs
}

intent describe_pattern(pairs: Any) -> Text {
    goal: Describe the geographic pattern of cities based on their latitudes.
}

entry main(input: Text) {
