pure fn remove_stop_words(sentence: Text) -> Text {
    stop_words = ["the", "a", "an", "is", "in", "on", "at", "to"]
    words = split(sentence, " ")
    filtered_words = []
    for word in words {
        if not contains(stop_words, word) {
            filtered_words = append(filtered_words, word)
        }
    }
    return join(filtered_words, " ")
}

intent summarize(text: Text) -> Text {
    goal: concise summary of the input text
}

entry main(sentence: Text) {
    cleaned_sentence = remove_stop_words(sentence)
    summary = summarize(cleaned_sentence)
    return summary
}
